// backend/routes/stripe.min.js
const router = require("express").Router();
const Stripe = require("stripe");
const stripe = new Stripe(process.env.STRIPE_SECRET_KEY, { apiVersion: "2024-06-20" });

router.post("/checkout", async (req, res) => {
  try {
    const { lookupKey, userId, email, productKey } = req.body;

    const prices = await stripe.prices.list({ lookup_keys: [lookupKey], limit: 1 });
    if (!prices.data.length) return res.status(400).json({ error: "Price not found" });

    const session = await stripe.checkout.sessions.create({
      mode: "subscription",
      line_items: [{ price: prices.data[0].id, quantity: 1 }],
      customer_email: email || undefined,
      success_url: `${process.env.APP_URL}/subscribe/success`,
      cancel_url: `${process.env.APP_URL}/subscribe/cancelled`,
      metadata: { userId: userId || "", productKey: productKey || "" },
    });

    res.json({ url: session.url });
  } catch (e) {
    console.error("checkout error", e);
    res.status(500).json({ error: e.message });
  }
});

module.exports = router;
